    96→    if (mask & AE_READABLE) ee.events |= EPOLLIN;
    97→    if (mask & AE_WRITABLE) ee.events |= EPOLLOUT;
    98→    ee.data.fd = fd;
    99→    if (mask != AE_NONE) {
   100→        epoll_ctl(state->epfd,EPOLL_CTL_MOD,fd,&ee);
   101→    } else {
